+            let page = sample_page(i as u8);
+            wal.append_frame(&cx, i, &page, i)
+                .unwrap_or_else(|e| panic!("append frame {i}: {e}"));
+        }
+        wal.sync(&cx, SyncFlags::NORMAL).expect("sync WAL");
+        assert_eq!(wal.frame_count(), 3, "pre-reset: 3 frames");
+
